28→/** If there's an action pending in the review queue, undo it and show a snackbar */
29→suspend fun FragmentActivity.undoAndShowSnackbar(duration: Int = Snackbar.LENGTH_SHORT) {
30→    withProgress {
31→        val changes = undoableOp {
32→            if (!undoAvailable()) {
33→                OpChangesAfterUndo.getDefaultInstance()
34→            } else {
35→                undo()
36→            }
37→        }
38→        val message = if (changes.operation.isEmpty()) {
39→            TR.actionsNothingToUndo()
40→        } else {
41→            TR.undoActionUndone(changes.operation)
42→        }
43→        showSnackbar(message, duration)
44→    }
45→}
